INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('esente diploma os titulares das prestações dos regimes não contributivos e equiparados, com exclusão dos titulares que beneficiem de pensões cujo montante corresponda ao valor da pensão mínima do regime geral.
  2 - (Revogado.)
  Artigo 3.º
  ...
  1 - O complemento extraordinário de solidariedade acresce ao montante da pensão social de velhice do regime não contributivo e de regimes equiparados, ainda que reduzidas por aplicação do disposto no artigo 9.º do Decreto-Lei n.º 464/80, de 13 de outubro.
  2 - (Revogado.)
